public int maxSubArray(int[] nums) {
    int maxSoFar = nums[0];
    int maxEndingHere = nums[0];

    for (int i = 1; i < nums.length; i++) {
        maxEndingHere = Math.max(nums[i], maxEndingHere + nums[i]);
        maxSoFar = Math.max(maxSoFar, maxEndingHere);
    }

    return maxSoFar;
}

public int maxSubArray(int[] nums) {
    return divConq(nums, 0, nums.length - 1);
}
private int divConq(int[] nums, int lo, int hi) {
    if (lo == hi) return nums[lo];
    int mid = (lo + hi) / 2;
    int left = divConq(nums, lo, mid);
    int right = divConq(nums, mid + 1, hi);
    int cross = crossSum(nums, lo, hi, mid);
    return Math.max(left, Math.max(right, cross));
}
private int crossSum(int[] nums, int lo, int hi, int mid) {
    int leftSum = Integer.MIN_VALUE, sum = 0;
    for (int i = mid; i >= lo; i--) { sum += nums[i]; leftSum = Math.max(leftSum, sum); }
    int rightSum = Integer.MIN_VALUE; sum = 0;
    for (int i = mid+1; i <= hi; i++) { sum += nums[i]; rightSum = Math.max(rightSum, sum); }
    return leftSum + rightSum;
}

