from typing import List

def max_sub_array(nums: List[int]) -> int:
    def div_conq(lo, hi):
        if lo == hi: return nums[lo]
        mid = (lo + hi) // 2
        left = div_conq(lo, mid)
        right = div_conq(mid + 1, hi)
        # cross sum
        left_sum = s = 0
        for i in range(mid, lo - 1, -1):
            s += nums[i]; left_sum = max(left_sum, s)
        right_sum = s = 0
        for i in range(mid + 1, hi + 1):
            s += nums[i]; right_sum = max(right_sum, s)
        return max(left, right, left_sum + right_sum)
    return div_conq(0, len(nums) - 1)
